function get_statistics(n){var i=n.getAttribute("data-type")!==null?n.getAttribute("data-type"):"overview",t=new XMLHttpRequest;t.open("GET","https://www.hockeytabeller.se/api/groups/get_"+i+"_as_html/"+n.getAttribute("data-group"),!0);t.onload=function(){t.status===200&&(n.insertAdjacentHTML("beforeend",t.response),apply_filter(n))};t.send()}function apply_filter(n){var r=n.getAttribute("data-filter")!==null?n.getAttribute("data-filter").split(","):[],i,t;if(r.length>0)for(i=n.getElementsByClassName("annytab-ht-team-container"),t=0;t<i.length;t++)r.includes(i[t].getAttribute("data-team"))||(i[t].style.display="none")}document.addEventListener("DOMContentLoaded",function(){for(var t=document.getElementsByClassName("hockeytabeller.se"),n=0;n<t.length;n++)get_statistics(t[n])},!1);